query GetCardFields($cardId: ID!) {
  card(id: $cardId) {
    id
    title
    fields {
      field {
        id
        label
        type
      }
      value          # human-readable value
      report_value   # normalized value (useful for numbers/selects)
      array_value
    }
  }
}

