=mutation ($pipeId: ID!, $fields: [FieldValueInput!]!) {
  createCard(input: { pipe_id: $pipeId, fields_attributes: $fields }) {
    card { id }
    user_errors { field message }
  }
}

=mutation ($cardId: ID!, $toAdd: [UndefinedInput!]!) {
  updateFieldsValues(input: { nodeId: $cardId values: [ { fieldId: "cards_de_contatos" value: $toAdd operation: ADD } ] }) {
    success
    userErrors { field message }
    updatedNode { ... on Card { id } }
  }
}

={{`mutation ($cardId: ID!, $toAdd: [UndefinedInput!]!) {
  updateFieldsValues(input: {
    nodeId: $cardId
    values: [ { fieldId: "${$json.fichaFieldId}" value: $toAdd operation: ADD } ]
  }) {
    success
    userErrors { field message }
    updatedNode { ... on Card { id } }
  }
}`}}
